SELECT * FROM leave_application
WHERE employee_id = #{employeeId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM leave_application
WHERE status = #{status}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COALESCE(SUM(days), 0)
FROM leave_application
WHERE employee_id = #{employeeId}
  AND leave_type = #{leaveType}
  AND status = 2  
  AND start_date <= #{endDate}
  AND end_date >= #{startDate}
